import os
import json
import base64
from datetime import datetime, timezone

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "")
PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT") or storage_client.project


def _parse_event(event, context):
    if event is not None:
        bucket_name = event.get("bucket")
        object_name = event.get("name")
        generation = event.get("generation")
        content_type = event.get("contentType")
        metageneration = event.get("metageneration")
        time_created = event.get("timeCreated")
        updated = event.get("updated")
        return {
            "bucket": bucket_name,
            "name": object_name,
            "generation": generation,
            "contentType": content_type,
            "metageneration": metageneration,
            "timeCreated": time_created,
            "updated": updated,
        }

    if context is not None:
        return {
            "bucket": getattr(context, "resource", {}).get("bucket") if hasattr(context, "resource") else None,
            "name": getattr(context, "resource", {}).get("name") if hasattr(context, "resource") else None,
            "generation": getattr(context, "event_id", None),
            "contentType": None,
            "metageneration": None,
            "timeCreated": None,
            "updated": None,
        }

    return {}


def _read_blob(bucket_name, object_name):
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name)
    data = blob.download_as_bytes()
    return blob, data


def _try_decode_text(data):
    try:
        return data.decode("utf-8")
    except Exception:
        return None


def _build_firestore_doc(bucket_name, object_name, blob, data):
    text = _try_decode_text(data)
    payload = {
        "bucket": bucket_name,
        "name": object_name,
        "size": blob.size,
        "content_type": blob.content_type,
        "crc32c": blob.crc32c,
        "md5_hash": blob.md5_hash,
        "generation": str(blob.generation) if blob.generation is not None else None,
        "metageneration": str(blob.metageneration) if blob.metageneration is not None else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "processed_at": datetime.now(timezone.utc).isoformat(),
    }

    if text is not None:
        payload["text_preview"] = text[:2000]
        payload["is_text"] = True
    else:
        payload["base64_preview"] = base64.b64encode(data[:1024]).decode("ascii")
        payload["is_text"] = False

    return payload


def _publish_message(topic_path, message):
    data = json.dumps(message, default=str).encode("utf-8")
    future = publisher.publish(topic_path, data=data, source="gcf", event_type="storage.object.processed")
    return future.result(timeout=30)


def process_file(event, context):
    info = _parse_event(event, context)
    bucket_name = info.get("bucket")
    object_name = info.get("name")

    if not bucket_name or not object_name:
        raise ValueError("Missing bucket or object name")

    blob, data = _read_blob(bucket_name, object_name)
    doc = _build_firestore_doc(bucket_name, object_name, blob, data)

    doc_id = f"{bucket_name}__{object_name}".replace("/", "__")
    firestore_client.collection("processed_files").document(doc_id).set(doc, merge=True)

    result = {
        "bucket": bucket_name,
        "name": object_name,
        "firestore_doc": doc_id,
        "processed_at": doc["processed_at"],
    }

    if PUBSUB_TOPIC:
        topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC) if "/" not in PUBSUB_TOPIC else PUBSUB_TOPIC
        message_id = _publish_message(topic_path, result)
        result["pubsub_message_id"] = message_id

    return result


def main(event, context):
    return process_file(event, context)